module RefModule(
    input [31:0] in_vector,
    output reg [5:0] out_count
);integer obf_i;
    reg [5:0] count;

    always @(*) begin
        count = 0;
        for (obf_i = 0; obf_i < 32; obf_i = obf_i + 1) begin
            if (in_vector[obf_i] == 1) begin
                count = count + 1;
            end
        end
        out_count = count;
    end

endmodule
